Intro Csharp RS232йҖҷзҜҮд»Ӣзҙ№йҖҸйҒҺRS232 Protocolе°ҚdeviceеҒҡwriteе’Ңreadж“ҚдҪңгҖӮеҲқе§ӢRS232йҖЈз·ҡ1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768SerialPort serialPort = new SerialPort();public bool Init(int _comPort, BaudRateType baudRateType, ScanType scanType)&#123; comPort = _comPort; try &#123; var comportName = string.Format(@"COM&#123;0&#125;", comPort); if (serialPort != null &amp;&amp; serialPort.IsOpen) &#123; serialPort.Close(); &#125; serialPort = new SerialPort &#123; PortName = comportName &#125;; switch (baudRateType) &#123; case BaudRateType.BaudRate9600: serialPort.BaudRate = 9600; break; case BaudRateType.BaudRate19200: serialPort.BaudRate = 19200; break; case BaudRateType.BaudRate38400: serialPort.BaudRate = 38400; break; case BaudRateType.BaudRate57600: serialPort.BaudRate = 57600; break; case BaudRateType.BaudRate115200: serialPort.BaudRate = 115200; break; default: serialPort.BaudRate = 19200; break; &#125; serialPort.Parity = Parity.None; serialPort.DataBits = 8; serialPort.StopBits = StopBits.One; serialPort.ReadBufferSize = 1024; serialPort.WriteBufferSize = 1024; if (serialPort != null &amp;&amp; !serialPort.IsOpen) &#123; try &#123; serialPort.Open(); &#125; catch (Exception ex) &#123; if (!MachineDataObj.IsTestAutoMode) &#123; LogUtil.logger.Error(Convert.ToString(ex)); &#125; serialPort = null; return false; &#125; &#125; this.scanType = scanType; openCom = 1; &#125; catch (Exception ex) &#123; TelegramBotType.FatalAndCallTelegram(Convert.ToString(ex)); &#125; return true;&#125;Form_Load еҲқе§ӢиЁӯе®ҡ1234serialPort.DataReceived += new SerialDataReceivedEventHandler(dataReceived);serialPort.DtrEnable = true;serialPort.RtsEnable = true;serialPort.ReadTimeout = 1000;Read Data via RS232 Protocol123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475private void dataReceived(object sender, SerialDataReceivedEventArgs e)&#123; if (serialPort.IsOpen) &#123; DateTime dateTimeNow = DateTime.Now; //dateTimeNow.GetDateTimeFormats(); textBoxReceive.Text += string.Format("&#123;0&#125;
", dateTimeNow); //dateTimeNow.GetDateTimeFormats('f')[0].ToString() + "
"; textBoxReceive.ForeColor = Color.Red; //ASCII if (radioButtonReceiveDataASCII.Checked == true) &#123; try &#123; String input = serialPort.ReadLine(); textBoxReceive.Text += input + "
"; // save data to file if (saveDataFS != null) &#123; byte[] info = new UTF8Encoding(true).GetBytes(input + "
"); saveDataFS.Write(info, 0, info.Length); &#125; &#125; catch(System.Exception ex) &#123; MessageBox.Show(ex.Message); return; &#125; textBoxReceive.SelectionStart = textBoxReceive.Text.Length; textBoxReceive.ScrollToCaret(); serialPort.DiscardInBuffer(); &#125; else //HEX &#123; try &#123; string input = serialPort.ReadLine(); char[] values = input.ToCharArray(); foreach (char letter in values) &#123; // Get the integral value of the character. int value = Convert.ToInt32(letter); // Convert the decimal value to a hexadecimal value in string form. string hexOutput = String.Format("&#123;0:X&#125;", value); textBoxReceive.AppendText(hexOutput + " "); textBoxReceive.SelectionStart = textBoxReceive.Text.Length; textBoxReceive.ScrollToCaret(); //textBoxReceive.Text += hexOutput + " "; &#125; // save data to file if (saveDataFS != null) &#123; byte[] info = new UTF8Encoding(true).GetBytes(input + "
"); saveDataFS.Write(info, 0, info.Length); &#125; &#125; catch(System.Exception ex) &#123; MessageBox.Show(ex.Message, "Error"); textBoxReceive.Text = ""; &#125; &#125; &#125; else &#123; MessageBox.Show("Com error"); &#125;&#125;Write Data via RS232 Protocol123456789101112131415161718192021222324252627282930private void buttonSendData_Click(object sender, EventArgs e)&#123; if (!serialPort.IsOpen) &#123; MessageBox.Show("Open comPort"); return; &#125; String strSend = textBoxSend.Text; if (radioButtonSendDataASCII.Checked == true) //Send ASCII &#123; serialPort.WriteLine(strSend);//еҸ‘йҖҒдёҖиЎҢж•°жҚ® &#125; else &#123; //Send 16йҖІеҲ¶з”ЁHEX char[] values = strSend.ToCharArray(); foreach (char letter in values) &#123; // Get the integral value of the character. int value = Convert.ToInt32(letter); // Convert the decimal value to a hexadecimal value in string form. string hexIutput = String.Format("&#123;0:X&#125;", value); serialPort.WriteLine(hexIutput); &#125; &#125;&#125;
